class Solution {
    public int minInsertions(String s) {
        int res = 0, need = 0;
        for (char c : s.toCharArray()) {
            if (c == '(') {
                need++;
            } else {
                if (need == 0) res++;
                else need--;
                need %= 2;
                if (need == 1) res++;
            }
        }
        res += need;
        return res;
    }
}
```
